INSERT INTO `z_forum` (`id`, `sticky`, `closed`, `first_post`, `last_post`, `section`, `icon_id`, `replies`, `views`, `author_aid`, `author_guid`, `post_text`, `post_topic`, `post_smile`, `post_date`, `last_edit_aid`, `edit_date`, `post_ip`) VALUES
(118, 0, 0, 118, 1699939036, 1, 0, 0, 0, 8776, 7786, '<center><b>Client Update and News</b></center>\r\n<p><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /><img style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" src=\"https://www.baiak-ilusion.com.br/images/letters/letter_martel_C.gif\" alt=\"\" /><span style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">aros amigos e colaboradores, &eacute; com grande entusiasmo que viemos informar que os novos clientes j&aacute; est&atilde;o dispon&iacute;veis para download.</span><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /><strong style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">D</strong><span style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">essa vez trouxemos algo in&eacute;dito para darmos continuidade na evolu&ccedil;&atilde;o do projeto. Estamos disponibilizando novos clientes que contam com uma grande variedade de novos itens, grande diversidade de novos outfits e o sistema completo de mounts, com todas as montarias incluindo as mais recentes.</span><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /></p>\r\n<center style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; background-color: #fff2db;\"><br /><strong>Algumas das novas montarias:</strong><br /><br /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/211.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/207.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/203.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/202.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/184.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/200.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/197.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/193.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/188.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/185.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/181.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/164.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/162.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/161.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/146.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/113.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/206.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/183.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/175.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/mounts/218.gif\" alt=\"\" /><br /><br /><br /><strong>Alguns dos novos outfits:</strong><br /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/113.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/112.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/111.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/110.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/108.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/73.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/106.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/62.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/104.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/102.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/99.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/98.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/96.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/95.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/94.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/92.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/91.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/89.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/88.gif\" alt=\"\" /><img src=\"https://cdn.baiak-ilusion.com/images/outfits/93.gif\" alt=\"\" /><br /><br /></center>\r\n<p><br style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\" /><span style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">Os clientes estar&atilde;o dispon&iacute;veis nas vers&otilde;es,&nbsp;</span><strong style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">Tradicional / Custom</strong><span style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">&nbsp;que s&atilde;o compat&iacute;veis com MageBot/Elfbot 8.60, e&nbsp;</span><strong style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">OTCV8</strong><span style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; text-align: justify; background-color: #fff2db;\">&nbsp;que possui bot pr&oacute;prio integrado no cliente. Para facilitar sua escolha:</span></p>\r\n<center style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 15px; background-color: #fff2db;\"><br />\r\n<ul>\r\n<li><strong>Tradicional</strong>: Conta com a identidade visual original da vers&atilde;o 8.60 com os efeitos e anima&ccedil;&otilde;es originais e possui os novos itens, outfits e montarias.&nbsp;<em><small style=\"font-size: 10px;\"><strong>*Compat&iacute;vel com Elfbot e Magebot</strong>.</small></em></li>\r\n</ul>\r\n</center>', 'Client Update and News', 0, 1699939036, 0, 0, '187.74.56.244');
