INSERT INTO `z_news_tickers` (`id`, `date`, `author`, `image_id`, `text`, `hide_ticker`) VALUES
(30, 1699921756, 8776, 0, '&#128203; <b>Relatório de atualizações</b> -  Diversos ajustes, correções e novas otimizações realizadas, muito em breve retornaremos com novas coordenadas referentes aos planos para os próximos dias e futuros updates no servidor.<br>Saiba as principais mudanças da última semana: <br><br>&#65515; Adição dos Bosses Jaul, Obojis e Tanjis (Invasões todos os <u>domingos as 16h</u>).<br>&#65515; Exercise Weapons agora dão 3 minutos de <i>stamina</i> a cada <b>3 minutos de treinamento</b>.<br>&#65515; Expiração das Frags passam de 24 horas para <b>15 horas</b>.<br>&#65515; Alguns dos novos monstros foram adicionados nas <a href=\"?subtopic=wiki&section=prey\">Preys</a> e <a href=\"?subtopic=wiki&section=dailyMonster\">Daily Monsters</a>.<br>&#65515; Algumas magias tiveram seus <i>exhausts</i> ajustados.<br>&#65515; Second Assassin Outfit passa para <i>10 behemoth claws</i>.<br>&#65515; Coloque o dinheiro na flexa e use \"<b>!tradeoff add, nome do item</b>\", para adicionar uma oferta de <b>compra</b>.<br>&#65515; Novos Monsters <i>13x</i> adicionado.<br>&#65515; Novos itens receberam <i>slots</i> de <a href=\"?subtopic=imbuiments\">imbuiments</a>.<br>&#65515; Estamos <b>muito mais estaveis</b>, retornamos os saves para o tempo normal.', 1),
(32, 1699921756, 8776, 4, 'Restart Server - 18/11 (15horas)', 1),
(34, 1699923964, 8776, 0, '&#9876; <b>Estamos Organizando</b> - um campeonato PvP (Guild versus Guild) e oferecendo prêmios interessantes. A premiação de 1k no Pix e 2k de pontos para o time vencedor.&#129340;', 0),
(36, 1699940812, 8776, 4, '<red>NEWS HUNTS<red> : Gnomprona, Falcon Bastion, Cobra Bastion e Buried Cathedral!', 0),
(37, 1699921756, 8776, 4, 'Start Server - 17/11 (15horas)', 0),
(38, 1700506434, 8776, 0, 'A necessidade do uso do nosso cliente sem a ocorrência de debugs. Se você tiver alguma dúvida ou precisar de assistência com relação a esse servidor em particular, por favor, forneça mais informações para que eu possa entender melhor e ajudar da melhor forma possível.', 0);
